    // Since N is up to 40, Meet-in-the-Middle (MITM) is appropriate.

    const half = Math.floor(n / 2);
    const nums1 = nums.slice(0, half);
    const nums2 = nums.slice(half);

    // Map to store all possible XOR sums from the first half and the number of elements used to achieve it.
    // Key: XOR sum, Value: Minimum number of elements used from nums1.
