        let currentXor = 0;
        let count = 0;
        for (let j = 0; j < nums1.length; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums1[j];
                count++;
            }
        }

        if (!map1.has(currentXor) || count < map1.get(currentXor)) {
            map1.set(currentXor, count);
        }
