    const map2 = new Map();

    // Generate all 2^(n-half) subset XOR sums for nums2
    for (let i = 0; i < (1 << nums2.length); i++) {
        let currentXor = 0;
        let count = 0;
        for (let j = 0; j < nums2.length; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums2[j];
                count++;
            }
        }

        if (!map2.has(currentXor) || count < map2.get(currentXor)) {
            map2.set(currentXor, count);
        }
    }

    let minRemovals = Infinity;

    // We are looking for XOR_sum1 ^ XOR_sum2 = target.
    // This means XOR_sum2 = target ^ XOR_sum1.
    for (const [xor1, count1] of map1.entries()) {
        const neededXor2 = target ^ xor1;

        if (map2.has(neededXor2)) {
            const count2 = map2.get(neededXor2);

            // Total elements kept = count1 + count2
            // Total removals = n - (count1 + count2)
            const keptCount = count1 + count2;
            const removals = n - keptCount;

            minRemovals = Math.min(minRemovals, removals);
        }
    }

    return minRemovals === Infinity ? -1 : minRemovals;
